  malphite: { diff: "TRICKY", tone: "#ff8b3d", tldr: "He stacks armor \u2014 build AD, boomerang-poke, dodge R.", breakdown: "Malphite stacks armor. Build AD/pen, boomerang-poke from range, and dodge his R engage.", dos: ["Build AD + armor pen", "Boomerang-poke from range", "Dodge his R engage"], donts: ["Auto-trade his passive", "Eat his R knockup", "Fight when his R is up"], key: { slot: "R", name: "Unstoppable Force", cd: "130s", note: "Un-dodgeable burst. Respect it.", winT: "ULT DOWN", winS: "Boomerang-W + R him." }, hold: "Hold Mega CC to peel \u2014 build pen; boomerang-poke his armor down and dodge his R.", tip: "He stacks armor \u2014 build AD/pen, boomerang-poke from range, and dodge his R engage.", win: "Build pen and boomerang-poke him." },
