  ornn: { diff: "EVEN", tone: "#e8b84b", tldr: "Boomerang %HP-poke his early \u2014 dodge his Q.", breakdown: "Both scale. Boomerang %HP-poke his early, dodge his Q wall-knockup, and Mega-CC.", dos: ["Boomerang %HP-poke his early", "Dodge his Q knockup", "Mega-CC his engage"], donts: ["Stand near walls for his Q", "Get brittle-procced", "Fall behind in scaling"], key: { slot: "Q", name: "Volcanic Rupture", cd: "10s", note: "Wall-knockup setup. Dodge it.", winT: "RUPTURE DOWN", winS: "Boomerang-W + R him." }, hold: "Hold Mega CC for his engage \u2014 boomerang %HP-poke his early and dodge his Q.", tip: "Both scale \u2014 boomerang %HP-poke his early, dodge his Q, and Mega-CC his engage.", win: "%HP-poke his early and out-scale." },
  poppy: { diff: "EVEN", tone: "#e8b84b", tldr: "Kite her E \u2014 boomerang-poke, mind her W vs Mega.", breakdown: "Poppy\u2019s W grounds dashes. Boomerang-poke from range, dodge her E, and Mega-CC her.", dos: ["Boomerang-poke from range", "Dodge her E wall-stun", "Mega-CC her"], donts: ["Get E-wall-stunned", "Mega-dash into her W", "Get R-knocked mid-combo"], key: { slot: "E", name: "Heroic Charge", cd: "14s", note: "Wall-pin stun. Dodge it.", winT: "CHARGE DOWN", winS: "Boomerang-W + R her." }, hold: "Hold Mega CC for when her W is down \u2014 her W grounds your hop, so time the GNAR! around it.", tip: "Boomerang-poke from range, dodge her E, and Mega-CC her when her W is down.", win: "Poke mini and Mega-CC off her W." },
