  akali: { diff: "TRICKY", tone: "#ff8b3d", tldr: "Build MR \u2014 boomerang-poke off shroud, Mega-CC.", breakdown: "Build MR, boomerang-poke her off her shroud, and Mega-CC her all-in.", dos: ["Build MR", "Boomerang-poke off her shroud", "Mega-CC her all-in"], donts: ["Fight her in the shroud", "Get Q-poked down", "Transform too late"], key: { slot: "W", name: "Twilight Shroud", cd: "18s", note: "Untargetable inside. Poke when down.", winT: "SHROUD DOWN", winS: "Boomerang-W + R her." }, hold: "Hold Mega CC for her all-in \u2014 GNAR! knockup interrupts her combo when she dives.", tip: "Build MR, boomerang-poke her off her shroud, and Mega-CC her all-in.", win: "Build MR and Mega-CC her all-in." },
