  gangplank: { diff: "EVEN", tone: "#e8b84b", tldr: "Boomerang-poke \u2014 pop his barrels, Mega-CC.", breakdown: "Pop his barrels in mini form, boomerang-poke, and Mega-CC his combo; out-scale together.", dos: ["Pop his barrels", "Boomerang-poke from range", "Mega-CC his combo"], donts: ["Eat a full barrel chain", "Let him free-scale", "Transform too late"], key: { slot: "E", name: "Powder Kegs", cd: "18s", note: "Pop barrels to deny poke + gold.", winT: "BARRELS CLEARED", winS: "Boomerang-W + R him." }, hold: "Hold Mega CC for his step-up \u2014 pop his barrels and boomerang-poke to deny his scaling.", tip: "Pop his barrels, boomerang-poke from range, and Mega-CC his combo \u2014 out-scale together.", win: "Pop barrels and out-scale him." },
  gnar: { diff: "MIRROR", tone: "#e8b84b", tldr: "Gnar mirror \u2014 whoever lands Mega-CC and wins the boomerang war wins.", breakdown: "Pure Gnar mirror: it\u2019s a boomerang-poke and rage-timing race. Whoever times Mega CC + the boomerang war better wins.", dos: ["Win the boomerang-poke war", "Time your Mega transform", "Mega-CC his Mega"], donts: ["Mistime your transform", "Eat his Mega all-in", "Fall behind in farm"], key: { slot: "R", name: "GNAR! (Mega Stun)", cd: "90s", note: "Whoever times Mega CC + boomerang better wins.", winT: "MINI FORM", winS: "Boomerang-W + R him." }, hold: "Hold Mega until HIS rage is low \u2014 transform when he\u2019s stuck in mini, then GNAR! all-in.", tip: "It\u2019s a boomerang + rage-timing mirror \u2014 win the poke war and transform Mega when he can\u2019t answer.", win: "Win the boomerang war and time Mega." },
  heimerdinger: { diff: "HARD", tone: "#ff5d6c", tldr: "His turrets out-poke you \u2014 build MR, Mega-dive his nest.", breakdown: "Heimer\u2019s turrets out-poke you. Build MR, boomerang his turrets, and Mega-dive him off his nest.", dos: ["Build MR", "Boomerang his turrets", "Mega-dive him off his nest"], donts: ["Dive a full nest raw", "Eat his E stun", "Poke-war into turrets"], key: { slot: "E", name: "CH-2 Grenade (Stun)", cd: "11s", note: "His self-peel stun. Dodge it.", winT: "GRENADE DOWN", winS: "Boomerang-W + R him." }, hold: "Hold Mega to dive his nest \u2014 GNAR! knockup + wall-stun lets you all-in him past the turrets.", tip: "Build MR, boomerang his turrets, and Mega-dive him off his nest with the wall-stun.", win: "Build MR and Mega-dive his nest." },
