  kayle: { diff: "FAVOURED", tone: "#3ddc97", tldr: "Crush her early \u2014 boomerang-poke and deny her CS.", breakdown: "Kayle is helpless early. Boomerang-poke and zone her off CS, and Mega all-in before her R.", dos: ["Boomerang-poke and zone her", "Deny her CS + XP", "Mega all-in before her R"], donts: ["Let her free-farm", "Fight late vs her R", "Transform too late"], key: { slot: "R", name: "Divine Judgment (Invuln)", cd: "100s", note: "Her get-out at 6. Bait it.", winT: "JUDGMENT DOWN", winS: "Boomerang-W + R her." }, hold: "Hold Mega to all-in her early \u2014 GNAR! knockup + wall-stun bursts her before she scales.", tip: "She\u2019s helpless early \u2014 boomerang-poke her off CS and Mega all-in before her R.", win: "Bully her early and deny CS." },
  kennen: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 boomerang-poke, Mega-CC his combo.", breakdown: "Build MR, boomerang-poke from range, and Mega-CC his combo; all-in when his E is down.", dos: ["Build MR", "Boomerang-poke from range", "Mega-CC his combo"], donts: ["Eat free Q pokes", "Get triple-stunned", "Fight into his R"], key: { slot: "E", name: "Lightning Rush", cd: "10s", note: "His escape. All-in when it\u2019s down.", winT: "E DOWN", winS: "Boomerang-W + R him." }, hold: "Hold Mega CC for his combo \u2014 GNAR! knockup interrupts his stun-stack when he steps up.", tip: "Build MR, boomerang-poke from range, and Mega-CC his combo \u2014 all-in when his E is spent.", win: "Build MR and Mega-CC his combo." },
  quinn: { diff: "TRICKY", tone: "#ff8b3d", tldr: "She pokes + kites \u2014 boomerang-poke back, Mega all-in.", breakdown: "Quinn out-pokes and kites. Boomerang-poke back, and Mega all-in her early before she scales.", dos: ["Boomerang-poke back", "Mega all-in her early", "Dodge her vault"], donts: ["Fight into her blind", "Poke-war with no answer", "Let her kite you out"], key: { slot: "E", name: "Vault (Dash/Blind)", cd: "11s", note: "Her self-peel. All-in when it\u2019s down.", winT: "VAULT DOWN", winS: "Boomerang-W + R her." }, hold: "Hold Mega to all-in her \u2014 GNAR! knockup + wall-stun locks her before she kites away.", tip: "Boomerang-poke back, dodge her vault, and Mega all-in her early before she scales.", win: "Trade poke and Mega all-in her." },
  rumble: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 boomerang-poke, dodge his R, Mega-CC.", breakdown: "Build MR, boomerang-poke from range, dodge his R line, and Mega-CC his engage.", dos: ["Build MR", "Boomerang-poke from range", "Dodge his R line"], donts: ["Extend into his danger-zone Q", "Stand in his R line", "Fight in his flamespitter"], key: { slot: "W", name: "Scrap Shield", cd: "6s", note: "Bait it, then commit.", winT: "SHIELD DOWN", winS: "Boomerang-W + R him." }, hold: "Hold Mega CC for his engage \u2014 build MR; boomerang-poke and dodge his R line.", tip: "Build MR, boomerang-poke from range, dodge his R, and Mega-CC his engage.", win: "Build MR and boomerang-poke him." },
  singed: { diff: "EVEN", tone: "#e8b84b", tldr: "Don\u2019t chase poison \u2014 boomerang-poke, Mega-CC his fling.", breakdown: "Never chase through poison. Boomerang-poke from range, and Mega-CC him when he commits a fling.", dos: ["Boomerang-poke from range", "Mega-CC his fling commit", "Punish his proxy waves"], donts: ["Chase through his Q poison", "Get E-flipped into goo", "Tunnel on the kill"], key: { slot: "E", name: "Fling", cd: "14s", note: "His flip. Mega-CC after it.", winT: "FLING DOWN", winS: "Boomerang-W + R him." }, hold: "Hold Mega CC for his fling commit \u2014 GNAR! knockup catches him when he over-extends.", tip: "Don\u2019t chase his poison \u2014 boomerang-poke from range and Mega-CC him when he commits a fling.", win: "Boomerang-poke and Mega-CC his commit." },
  swain: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 boomerang-poke, dodge his E root.", breakdown: "Build MR, boomerang-poke from range, dodge his E root, and anti-heal his R drain.", dos: ["Build MR + anti-heal", "Boomerang-poke from range", "Dodge his E root"], donts: ["Fight into his R drain", "Get E-rooted", "Fight a long brawl"], key: { slot: "R", name: "Demonic Ascension", cd: "100s", note: "His drain. Poke when it\u2019s down.", winT: "ASCENSION DOWN", winS: "Boomerang-W + R him." }, hold: "Hold Mega CC for when his R is down \u2014 build MR; boomerang-poke and dodge his E root.", tip: "Build MR, boomerang-poke from range, dodge his E root, and anti-heal his R drain.", win: "Build MR and dodge his E." },
  teemo: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 boomerang-poke from range, dodge shrooms.", breakdown: "Teemo blinds autos (not boomerangs). Build MR, boomerang-poke from range, and dodge shrooms.", dos: ["Build MR + dodge shrooms", "Boomerang-poke from range", "Mega-CC his approach"], donts: ["Auto into his blind", "Chase through shrooms", "Fight low with no escape"], key: { slot: "Q", name: "Blinding Dart", cd: "7s", note: "Blinds autos \u2014 NOT your boomerang.", winT: "BLIND DOWN", winS: "Boomerang-W + R him." }, hold: "Hold Mega CC for his approach \u2014 his blind stops autos, not your boomerang; poke freely.", tip: "His blind stops autos but NOT your boomerang \u2014 build MR, boomerang-poke from range, and dodge shrooms.", win: "Boomerang-poke through his blind." },
  vladimir: { diff: "EVEN", tone: "#e8b84b", tldr: "Bully him early \u2014 build MR, boomerang-poke, bait pool.", breakdown: "Vlad is weak early. Build MR, boomerang-poke and bully him, and bait his pool.", dos: ["Boomerang-poke and bully early", "Build MR + anti-heal", "Bait his pool"], donts: ["Let him pool your combo", "Stack pure HP vs %damage", "Let him free-scale"], key: { slot: "W", name: "Sanguine Pool", cd: "22s", note: "Dodges your combo. Bait it.", winT: "POOL DOWN", winS: "Boomerang-W + R him." }, hold: "Hold Mega CC \u2014 bait his pool first, then GNAR! all-in when he can\u2019t dodge.", tip: "He\u2019s weak early \u2014 boomerang-poke and bully him, bait his pool, and Mega-CC when it\u2019s down.", win: "Bully him early and bait his pool." },
